WGCNA Tutorial 2Official WebsitePaper: Peter Langfelder, 2008 Weighted correlation network analysis (WGCNA) can be used for finding clusters (modules) of highly correlated genes, for summarizing such clusters using the module eigengene or an intramodular hub gene, for relating modules to one another and to external sample traits (using eigengene network methodology), and for calculating module membership measures. Play list for Network Analysis Install12345# Mirrors# options(&quot;repos&quot; = c(CRAN=&quot;https://mirrors.tuna.tsinghua.edu.cn/CRAN/&quot;))# options(BioC_mirror=&quot;https://mirrors.tuna.tsinghua.edu.cn/bioconductor&quot;)install.packages(&quot;BiocManager&quot;)BiocManager::install(&quot;WGCNA&quot;) Data: Female data Male data 1. Data Preparation1.1 Loading DataSetThe data sets contain roughly 130 samples each. Note that each row corresponds to a gene and column to asample or auxiliary information. 12345678library(WGCNA)# Reading Dataoptions(stringsAsFactors = FALSE)#Read in the female liver data setfemData = read.csv(&quot;LiverFemale3600.csv&quot;)# Read in the male liver data setmaleData = read.csv(&quot;LiverMale3600.csv&quot;) 1.2 Groups in List1234567891011121314151617# We work with two sets:nSets = 2;# For easier labeling of plots, create a vector holding descriptive names of the two sets.setLabels = c(&quot;Female liver&quot;, &quot;Male liver&quot;)shortLabels = c(&quot;Female&quot;, &quot;Male&quot;)# Form multi-set expression data: columns starting from 9 contain actual expression data.multiExpr = vector(mode = &quot;list&quot;, length = nSets)multiExpr[[1]] = list(data = as.data.frame(t(femData[-c(1:8)])));names(multiExpr[[1]]$data) = femData$substanceBXH;rownames(multiExpr[[1]]$data) = names(femData)[-c(1:8)];multiExpr[[2]] = list(data = as.data.frame(t(maleData[-c(1:8)])));names(multiExpr[[2]]$data) = maleData$substanceBXH;rownames(multiExpr[[2]]$data) = names(maleData)[-c(1:8)];# Check that the data has the correct format for many functions operating on multiple sets:exprSize = checkSets(multiExpr) 1.3 Rudimentary data cleaning and outlier removalCheck that all genes and samples have sufficiently low numbers of missing values. 1234567891011121314151617181920gsg = goodSamplesGenesMS(multiExpr, verbose = 3);gsg$allOKif (!gsg$allOK){ # Print information about the removed genes: if (sum(!gsg$goodGenes) &gt; 0) printFlush(paste(&quot;Removing genes:&quot;, paste(names(multiExpr[[1]]$data)[!gsg$goodGenes], collapse = &quot;, &quot;))) for (set in 1:exprSize$nSets) { if (sum(!gsg$goodSamples[[set]])) printFlush(paste(&quot;In set&quot;, setLabels[set], &quot;removing samples&quot;, paste(rownames(multiExpr[[set]]$data)[!gsg$goodSamples[[set]]], collapse = &quot;, &quot;))) # Remove the offending genes and samples multiExpr[[set]]$data = multiExpr[[set]]$data[gsg$goodSamples[[set]], gsg$goodGenes]; } # Update exprSize exprSize = checkSets(multiExpr)} 1.4 Cluster1234567891011sampleTrees = list()for (set in 1:nSets){ sampleTrees[[set]] = hclust(dist(multiExpr[[set]]$data), method = &quot;average&quot;)}par(mfrow=c(2,1))par(mar = c(0, 4, 2, 0))for (set in 1:nSets) plot(sampleTrees[[set]], main = paste(&quot;Sample clustering on all genes in&quot;, setLabels[set]), xlab=&quot;&quot;, sub=&quot;&quot;, cex = 0.7) By inspection, there seems to be one outlier in the female data set, and no obvious outliers in the male set. Wenow remove the female outlier using a semi-automatic code that only requires a choice of a height cut 1.5 Remove Outlier1234567891011121314151617181920212223242526272829# Choose the &quot;base&quot; cut height for the female data setbaseHeight = 16# Adjust the cut height for the male data set for the number of samplescutHeights = c(16, 16*exprSize$nSamples[2]/exprSize$nSamples[1]);# Re-plot the dendrograms including the cut linespng(file = &quot;SampleClustering.png&quot;);par(mfrow=c(2,1))par(mar = c(0, 4, 2, 0))for (set in 1:nSets){ plot(sampleTrees[[set]], main = paste(&quot;Sample clustering on all genes in&quot;, setLabels[set]), xlab=&quot;&quot;, sub=&quot;&quot;, cex = 0.7); abline(h=cutHeights[set], col = &quot;red&quot;);}dev.off();# Removing outlierfor (set in 1:nSets){ # Find clusters cut by the line labels = cutreeStatic(sampleTrees[[set]], cutHeight = cutHeights[set]) # Keep the largest one (labeled by the number 1) keep = (labels==1) multiExpr[[set]]$data = multiExpr[[set]]$data[keep, ]}collectGarbage();# Check the size of the leftover dataexprSize = checkSets(multiExpr)exprSize 1.6 Loading Clinical Trait Data123456789101112131415161718192021traitData = read.csv(&quot;ClinicalTraits.csv&quot;);# remove columns that hold information we do not need.allTraits = traitData[, -c(31, 16)];allTraits = allTraits[, c(2, 11:36) ];# See how big the traits are and what are the trait and sample namesdim(allTraits)names(allTraits)allTraits$Mice# Form a multi-set structure that will hold the clinical traits.Traits = vector(mode=&quot;list&quot;, length = nSets);for (set in 1:nSets){ setSamples = rownames(multiExpr[[set]]$data); traitRows = match(setSamples, allTraits$Mice); Traits[[set]] = list(data = allTraits[traitRows, -1]); rownames(Traits[[set]]$data) = allTraits[traitRows, 1];}collectGarbage();# Define data set dimensionsnGenes = exprSize$nGenes;nSamples = exprSize$nSamples; 2. Network Construction and Module Detection123456789graph LR; START(Network construction) Net1(one-step network construction) Net2(Step-by-step network construction) Net3(automatic block-wise network construction) START--&gt;|Minimum Effort|Net1; START--&gt;|Customized/Alternate Methods|Net2; START--&gt;|Large Data Set|Net3; 2.1 One-Step Network Construction and Module Detection123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354# Choose a set of soft-thresholding powerspowers = c(seq(4,10,by=1), seq(12,20, by=2));# Initialize a list to hold the results of scale-free analysispowerTables = vector(mode = &quot;list&quot;, length = nSets);# Call the network topology analysis function for each set in turnfor (set in 1:nSets) powerTables[[set]] = list(data = pickSoftThreshold(multiExpr[[set]]$data, powerVector=powers, verbose = 2)[[2]]);collectGarbage();# Plot the results:colors = c(&quot;black&quot;, &quot;red&quot;)# Will plot these columns of the returned scale free analysis tablesplotCols = c(2,5,6,7)colNames = c(&quot;Scale Free Topology Model Fit&quot;, &quot;Mean connectivity&quot;, &quot;Median connectivity&quot;,&quot;Max connectivity&quot;);# Get the minima and maxima of the plotted pointsylim = matrix(NA, nrow = 2, ncol = 4);for (set in 1:nSets){ for (col in 1:length(plotCols)) { ylim[1, col] = min(ylim[1, col], powerTables[[set]]$data[, plotCols[col]], na.rm = TRUE); ylim[2, col] = max(ylim[2, col], powerTables[[set]]$data[, plotCols[col]], na.rm = TRUE); }}# Plot the quantities in the chosen columns vs. the soft thresholding powersizeGrWindow(8, 6)png(file = &quot;scaleFreeAnalysis.png&quot;)par(mfcol = c(2,2));par(mar = c(4.2, 4.2 , 2.2, 0.5))cex1 = 0.7;for (col in 1:length(plotCols)) for (set in 1:nSets){ if (set==1) { plot(powerTables[[set]]$data[,1], -sign(powerTables[[set]]$data[,3])*powerTables[[set]]$data[,2], xlab=&quot;Soft Threshold (power)&quot;,ylab=colNames[col],type=&quot;n&quot;, ylim = ylim[, col], main = colNames[col]); addGrid(); } if (col==1) { text(powerTables[[set]]$data[,1], -sign(powerTables[[set]]$data[,3])*powerTables[[set]]$data[,2], labels=powers,cex=cex1,col=colors[set]); } else text(powerTables[[set]]$data[,1], powerTables[[set]]$data[,plotCols[col]], labels=powers,cex=cex1,col=colors[set]); if (col==1) { legend(&quot;bottomright&quot;, legend = setLabels, col = colors, pch = 20) ; } else legend(&quot;topright&quot;, legend = setLabels, col = colors, pch = 20) ;}dev.off(); 2.2 Network construction and consensus module detectionAttention: We have chosen the soft thresholding power 6, minimum module size 30, the module detection sensitivity deepSplit 2, cut height for merging of modules 0.20 (implying that modules whose eigengenes are correlated above 1 − 0.2 = 0.8 will be merged), we requested that the function return numeric module labels rather than color labels, we have effectively turned off reassigning genes based on their module eigengene-based connectivity KME, and we have instructed the code to save the calculated consensus topological overlap. In this example most of them are left at their default value. We encourage the user to read the help file provided within the package in the R environment and experiment with tweaking the network construction and module detection parameters. The potential reward is, of course, better (biologically more relevant) results of the analysis. 123456net = blockwiseConsensusModules( multiExpr, power = 6, minModuleSize = 30, deepSplit = 2, pamRespectsDendro = FALSE, mergeCutHeight = 0.25, numericLabels = TRUE, minKMEtoStay = 0, saveTOMs = TRUE, verbose = 5) 2.3 Model Extract123456789101112131415consMEs = net$multiMEs;moduleLabels = net$colors;# Convert the numeric labels to color labelsmoduleColors = labels2colors(moduleLabels)consTree = net$dendrograms[[1]]sizeGrWindow(8,6);png(file = &quot;ConsensusDendrogram-auto.png&quot;, wi = 600, he = 340)plotDendroAndColors(consTree, moduleColors, &quot;Module colors&quot;, dendroLabels = FALSE, hang = 0.03, addGuide = TRUE, guideHang = 0.05, main = &quot;Consensus gene dendrogram and module colors&quot;)dev.off() 3. Relating the consensus modules to female set-specific modules3.1 datExpr(WGCNA Tutorial 1, 1-2) 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647femData = read.csv(&quot;LiverFemale3600.csv&quot;);datExpr0 = as.data.frame(t(femData[, -c(1:8)]));names(datExpr0) = femData$substanceBXH;rownames(datExpr0) = names(femData)[-c(1:8)];gsg = goodSamplesGenes(datExpr0, verbose = 3);gsg$allOKif (!gsg$allOK){ if (sum(!gsg$goodGenes)&gt;0) printFlush(paste(&quot;Removing genes:&quot;, paste(names(datExpr0)[!gsg$goodGenes], collapse = &quot;, &quot;))); if (sum(!gsg$goodSamples)&gt;0) printFlush(paste(&quot;Removing samples:&quot;, paste(rownames(datExpr0)[!gsg$goodSamples], collapse = &quot;, &quot;))); datExpr0 = datExpr0[gsg$goodSamples, gsg$goodGenes]}sampleTree = hclust(dist(datExpr0), method = &quot;average&quot;);clust = cutreeStatic(sampleTree, cutHeight = 15, minSize = 10)keepSamples = (clust==1)datExpr = datExpr0[keepSamples, ]nGenes = ncol(datExpr)nSamples = nrow(datExpr)traitData = read.csv(&quot;ClinicalTraits.csv&quot;);dim(traitData)names(traitData)allTraits = traitData[, -c(31, 16)];allTraits = allTraits[, c(2, 11:36) ];dim(allTraits)names(allTraits)femaleSamples = rownames(datExpr);traitRows = match(femaleSamples, allTraits$Mice);datTraits = allTraits[traitRows, -1];rownames(datTraits) = allTraits[traitRows, 1];collectGarbage()sampleTree2 = hclust(dist(datExpr), method = &quot;average&quot;)traitColors = numbers2colors(datTraits, signed = FALSE);powers = c(c(1:10), seq(from = 12, to=20, by=2))sft = pickSoftThreshold(datExpr, powerVector = powers, verbose = 5)net = blockwiseModules(datExpr, power = 6, TOMType = &quot;unsigned&quot;, minModuleSize = 30, reassignThreshold = 0, mergeCutHeight = 0.25, numericLabels = TRUE, pamRespectsDendro = FALSE, saveTOMs = TRUE, saveTOMFileBase = &quot;femaleMouseTOM&quot;, verbose = 3)moduleLabels = net$colorsmoduleColors = labels2colors(net$colors)MEs = net$MEs;geneTree = net$dendrograms[[1]] 3.2 Relating consensus modules to female set-specific modules12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152femaleLabels = moduleLabels;femaleColors = moduleColors;femaleTree = geneTree;femaleMEs = orderMEs(MEs, greyName = &quot;ME0&quot;);# Isolate the module labels in the order they appear in ordered module eigengenesfemModuleLabels = substring(names(femaleMEs), 3)consModuleLabels = substring(names(consMEs[[1]]$data), 3)# Convert the numeric module labels to color labelsfemModules = labels2colors(as.numeric(femModuleLabels))consModules = labels2colors(as.numeric(consModuleLabels))# Numbers of female and consensus modulesnFemMods = length(femModules)nConsMods = length(consModules)# Initialize tables of p-values and of the corresponding countspTable = matrix(0, nrow = nFemMods, ncol = nConsMods);CountTbl = matrix(0, nrow = nFemMods, ncol = nConsMods);# Execute all pairwaise comparisonsfor (fmod in 1:nFemMods) for (cmod in 1:nConsMods) { femMembers = (femaleColors == femModules[fmod]); consMembers = (moduleColors == consModules[cmod]); pTable[fmod, cmod] = -log10(fisher.test(femMembers, consMembers, alternative = &quot;greater&quot;)$p.value); CountTbl[fmod, cmod] = sum(femaleColors == femModules[fmod] &amp; moduleColors == consModules[cmod]) }# Truncate p values smaller than 10^{-50} to 10^{-50}pTable[is.infinite(pTable)] = 1.3*max(pTable[is.finite(pTable)]);pTable[pTable&gt;50 ] = 50 ;# Marginal counts (really module sizes)femModTotals = apply(CountTbl, 1, sum)consModTotals = apply(CountTbl, 2, sum)# Actual plottingsizeGrWindow(10,7 );#png(file = &quot;ConsensusVsFemaleModules.png&quot;, wi = 500, he = 400);par(mfrow=c(1,1));par(cex = 1.0);par(mar=c(8, 10.4, 2.7, 1)+0.3);# Use function labeledHeatmap to produce the color-coded table with all the trimmingslabeledHeatmap(Matrix = pTable, xLabels = paste(&quot; &quot;, consModules), yLabels = paste(&quot; &quot;, femModules), colorLabels = TRUE, xSymbols = paste(&quot;Cons &quot;, consModules, &quot;: &quot;, consModTotals, sep=&quot;&quot;), ySymbols = paste(&quot;Fem &quot;, femModules, &quot;: &quot;, femModTotals, sep=&quot;&quot;), textMatrix = CountTbl, colors = greenWhiteRed(100)[50:100], main = &quot;Correspondence of Female set-specific and Female-Male consensus modules&quot;, cex.text = 1.0, cex.lab = 1.0, setStdMargins = FALSE); 4. Consensus module to traits4.1 Correlation123456789101112131415161718192021222324252627282930313233343536moduleTraitCor = list();moduleTraitPvalue = list();# Calculate the correlationsfor (set in 1:nSets){ moduleTraitCor[[set]] = cor(consMEs[[set]]$data, Traits[[set]]$data, use = &quot;p&quot;); moduleTraitPvalue[[set]] = corPvalueFisher(moduleTraitCor[[set]], exprSize$nSamples[set]);}# Convert numerical lables to colors for labeling of modules in the plotMEColors = labels2colors(as.numeric(substring(names(consMEs[[1]]$data), 3)));MEColorNames = paste(&quot;ME&quot;, MEColors, sep=&quot;&quot;);# Open a suitably sized window (the user should change the window size if necessary)sizeGrWindow(10,7)#png(file = &quot;ModuleTraitRelationships-female.png&quot;, wi = 800, he = 560);# Plot the module-trait relationship table for set number 1set = 1textMatrix = paste(signif(moduleTraitCor[[set]], 2), &quot;
(&quot;, signif(moduleTraitPvalue[[set]], 1), &quot;)&quot;, sep = &quot;&quot;);dim(textMatrix) = dim(moduleTraitCor[[set]])par(mar = c(6, 8.8, 3, 2.2));labeledHeatmap(Matrix = moduleTraitCor[[set]], xLabels = names(Traits[[set]]$data), yLabels = MEColorNames, ySymbols = MEColorNames, colorLabels = FALSE, colors = greenWhiteRed(50), textMatrix = textMatrix, setStdMargins = FALSE, cex.text = 0.5, zlim = c(-1,1), main = paste(&quot;Module--trait relationships in&quot;, setLabels[set]))#dev.off(); 1234567891011121314151617181920# Plot the module-trait relationship table for set number 2set = 2textMatrix = paste(signif(moduleTraitCor[[set]], 2), &quot;
(&quot;, signif(moduleTraitPvalue[[set]], 1), &quot;)&quot;, sep = &quot;&quot;);dim(textMatrix) = dim(moduleTraitCor[[set]])sizeGrWindow(10,7)#png(file = &quot;ModuleTraitRelationships-male.png&quot;, wi = 800, he = 560);par(mar = c(6, 8.8, 3, 2.2));labeledHeatmap(Matrix = moduleTraitCor[[set]], xLabels = names(Traits[[set]]$data), yLabels = MEColorNames, ySymbols = MEColorNames, colorLabels = FALSE, colors = greenWhiteRed(50), textMatrix = textMatrix, setStdMargins = FALSE, cex.text = 0.5, zlim = c(-1,1), main = paste(&quot;Module--trait relationships in&quot;, setLabels[set]))dev.off(); 12345678910111213141516171819202122232425262728293031# Initialize matrices to hold the consensus correlation and p-valueconsensusCor = matrix(NA, nrow(moduleTraitCor[[1]]), ncol(moduleTraitCor[[1]]));consensusPvalue = matrix(NA, nrow(moduleTraitCor[[1]]), ncol(moduleTraitCor[[1]]));# Find consensus negative correlationsnegative = moduleTraitCor[[1]] &lt; 0 &amp; moduleTraitCor[[2]] &lt; 0;consensusCor[negative] = pmax(moduleTraitCor[[1]][negative], moduleTraitCor[[2]][negative]);consensusPvalue[negative] = pmax(moduleTraitPvalue[[1]][negative], moduleTraitPvalue[[2]][negative]);# Find consensus positive correlationspositive = moduleTraitCor[[1]] &gt; 0 &amp; moduleTraitCor[[2]] &gt; 0;consensusCor[positive] = pmin(moduleTraitCor[[1]][positive], moduleTraitCor[[2]][positive]);consensusPvalue[positive] = pmax(moduleTraitPvalue[[1]][positive], moduleTraitPvalue[[2]][positive]);textMatrix = paste(signif(consensusCor, 2), &quot;
(&quot;, signif(consensusPvalue, 1), &quot;)&quot;, sep = &quot;&quot;);dim(textMatrix) = dim(moduleTraitCor[[set]])sizeGrWindow(10,7)png(file = &quot;ModuleTraitRelationships-consensus.png&quot;, wi = 800, he = 560);par(mar = c(6, 8.8, 3, 2.2));labeledHeatmap(Matrix = consensusCor, xLabels = names(Traits[[set]]$data), yLabels = MEColorNames, ySymbols = MEColorNames, colorLabels = FALSE, colors = greenWhiteRed(50), textMatrix = textMatrix, setStdMargins = FALSE, cex.text = 0.5, zlim = c(-1,1), main = paste(&quot;Consensus module--trait relationships across
&quot;, paste(setLabels, collapse = &quot; and &quot;))) 4.2 Exporting results of the network analysis123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051file = gzfile(description = &quot;GeneAnnotation.csv.gz&quot;);annot = read.csv(file = file);# Match probes in the data set to the probe IDs in the annotation fileprobes = names(multiExpr[[1]]$data)probes2annot = match(probes, annot$substanceBXH)consMEs.unord = multiSetMEs(multiExpr, universalColors = moduleLabels, excludeGrey = TRUE)GS = list();kME = list();for (set in 1:nSets){ GS[[set]] = corAndPvalue(multiExpr[[set]]$data, Traits[[set]]$data); kME[[set]] = corAndPvalue(multiExpr[[set]]$data, consMEs.unord[[set]]$data);}GS.metaZ = (GS[[1]]$Z + GS[[2]]$Z)/sqrt(2);kME.metaZ = (kME[[1]]$Z + kME[[2]]$Z)/sqrt(2);GS.metaP = 2*pnorm(abs(GS.metaZ), lower.tail = FALSE);kME.metaP = 2*pnorm(abs(kME.metaZ), lower.tail = FALSE);GSmat = rbind(GS[[1]]$cor, GS[[2]]$cor, GS[[1]]$p, GS[[2]]$p, GS.metaZ, GS.metaP);nTraits = checkSets(Traits)$nGenestraitNames = colnames(Traits[[1]]$data)dim(GSmat) = c(nGenes, 6*nTraits)rownames(GSmat) = probes;colnames(GSmat) = spaste( c(&quot;GS.set1.&quot;, &quot;GS.set2.&quot;, &quot;p.GS.set1.&quot;, &quot;p.GS.set2.&quot;, &quot;Z.GS.meta.&quot;, &quot;p.GS.meta&quot;), rep(traitNames, rep(6, nTraits)))# Same code for kME:kMEmat = rbind(kME[[1]]$cor, kME[[2]]$cor, kME[[1]]$p, kME[[2]]$p, kME.metaZ, kME.metaP);MEnames = colnames(consMEs.unord[[1]]$data);nMEs = checkSets(consMEs.unord)$nGenesdim(kMEmat) = c(nGenes, 6*nMEs)rownames(kMEmat) = probes;colnames(kMEmat) = spaste( c(&quot;kME.set1.&quot;, &quot;kME.set2.&quot;, &quot;p.kME.set1.&quot;, &quot;p.kME.set2.&quot;, &quot;Z.kME.meta.&quot;, &quot;p.kME.meta&quot;), rep(MEnames, rep(6, nMEs)))info = data.frame(Probe = probes, GeneSymbol = annot$gene_symbol[probes2annot], EntrezID = annot$LocusLinkID[probes2annot], ModuleLabel = moduleLabels, ModuleColor = labels2colors(moduleLabels), GSmat, kMEmat);write.csv(info, file = &quot;consensusAnalysis-CombinedNetworkResults.csv&quot;, row.names = FALSE, quote = FALSE); 5. Relationships among modules and traits12345678910111213141516171819# Create a variable weight that will hold just the body weight of mice in both setsweight = vector(mode = &quot;list&quot;, length = nSets);for (set in 1:nSets){ weight[[set]] = list(data = as.data.frame(Traits[[set]]$data$weight_g)); names(weight[[set]]$data) = &quot;weight&quot;}# Recalculate consMEs to give them color namesconsMEsC = multiSetMEs(multiExpr, universalColors = moduleColors);# We add the weight trait to the eigengenes and order them by consesus hierarchical clustering:MET = consensusOrderMEs(addTraitToMEs(consMEsC, weight));sizeGrWindow(8,10);#png(file = &quot;EigengeneNetworks.png&quot;, width= 480, height = 600);par(cex = 0.9)plotEigengeneNetworks(MET, setLabels, marDendro = c(0,2,2,1), marHeatmap = c(3,3,2,1), zlimPreservation = c(0.5, 1), xLabelsAngle = 90)# dev.off(); github: https://github.com/Karobbenblog: Karobben.github.ioR 语言画图索引: https://karobben.github.io/R/R-index.html

EdgerExample form TrinityExpression DifferentialAttention: Make sure Trinity is installed because this scripts needs few functions from re-packaged scripts. If you didn’t install the Trinity, please download heatmap.3.R misc_rnaseq_funcs pairs3.R vioplot2.R from Github, or paste them to your codes instead of source them. (I paste this three codes at the end of the page) This script is running the differential expression counts. So, make sure you are handling an appropriate matrix. 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182838485868788899091library(cluster)library(Biobase)library(qvalue)library(fastcluster)options(stringsAsFactors = FALSE)NO_REUSE = F# try to reuse earlier-loaded data if possibleif (file.exists(&quot;diffExpr.P1e-5_C2.matrix.RData&quot;) &amp;&amp; ! NO_REUSE) { print('RESTORING DATA FROM EARLIER ANALYSIS') load(&quot;diffExpr.P1e-5_C2.matrix.RData&quot;)} else { # loading Count matrix print('Reading matrix file.') primary_data = read.table(&quot;diffExpr.P1e-5_C2.matrix&quot;, header=T, com='', row.names=1, check.names=F, sep='	') primary_data = as.matrix(primary_data)}# reading repackaged R function from scripts# similar like import File/lib.py in pythonsource(&quot;/home/ken/Biosoft/trinityrnaseq-Trinity-v2.8.4/Analysis/DifferentialExpression/R/heatmap.3.R&quot;)source(&quot;/home/ken/Biosoft/trinityrnaseq-Trinity-v2.8.4/Analysis/DifferentialExpression/R/misc_rnaseq_funcs.R&quot;)source(&quot;/home/ken/Biosoft/trinityrnaseq-Trinity-v2.8.4/Analysis/DifferentialExpression/R/pairs3.R&quot;)source(&quot;/home/ken/Biosoft/trinityrnaseq-Trinity-v2.8.4/Analysis/DifferentialExpression/R/vioplot2.R&quot;)data = primary_datamyheatcol = colorpanel(75, 'purple','black','yellow')sample_types = colnames(data)nsamples = length(sample_types)sample_colors = rainbow(nsamples)sample_type_list = list()for (i in 1:nsamples) { sample_type_list[[sample_types[