 col = rainbow(num_colors) } else { num_colors = length(col) } by = match.arg(by) if (by == &quot;matrix&quot;) { min_val = min(matrix_m, na.rm=T) matrix_m = matrix_m - min_val max_val = max(matrix_m, na.rm=T) matrix_m = matrix_m / max_val * num_colors #print(matrix_m) matrix_m = apply(matrix_m, 1:2, function(x) ifelse (x&lt;1, as.character(col[1]), as.character(col[x]))); matrix_m = matrix(as.character(matrix_m), nrow=dim(matrix_m)[1]) } else { row_or_col_only_color_selector_func = function(x) { a = min(x, na.rm=T); b = max(x, na.rm=T); c = (x-a)/(b-a) * num_colors; c = round(c); c = ifelse (c&lt;1, 1, c); #print(paste(c(&quot;color selection: (a)&quot;, a, &quot; (b)&quot;, b, &quot; (c)&quot;, paste(c, sep=',')))); colors = as.character(col[c]); return(colors); } if (by == &quot;row&quot;) { matrix_m = apply(matrix_m, 1, row_or_col_only_color_selector_func); print(matrix_m) print(&quot;dim matrix_m after apply&quot;); print(dim(matrix_m)) matrix_m = t(matrix_m); print(&quot;dim matrix_m after transpose: &quot;); print(dim(matrix_m)) } else { # by column matrix_m = apply(matrix_m, 2, row_or_col_only_color_selector_func); } } #print(matrix_m) return(matrix_m)}sample_matrix_to_color_assignments = function(sampleAnnotationsMatrix, colors) { if (missing(colors)) colors = rainbow(nrow(sampleAnnotationsMatrix)) nsamples = nrow(sampleAnnotationsMatrix); if (length(colors) &lt; nrow(sampleAnnotationsMatrix)) stop(&quot;Error, only &quot;, length(colors), &quot; colors specified, but have &quot;, nsamples, &quot; samples&quot;); for (i in 1:nrow(sampleAnnotationsMatrix)) { c = colors[i] sampleAnnotationsMatrix[i,] = sapply(sampleAnnotationsMatrix[i,], function(x) ifelse( x, as.character(c), 'white')) } return(sampleAnnotationsMatrix);} pairs3.# from: https://github.com/trinityrnaseq/trinityrnaseq/blob/master/Analysis/DifferentialExpression/R/pairs3.R## snagged from: http://stackoverflow.com/questions/9680783/how-can-i-change-the-axis-position-for-pairs# modified to include function for modifying X/Y values.pairs3 &lt;- function (x, labels, XY_convert_fun = NULL, CustomColorFun = NULL, panel = points, ..., lower.panel = panel, upper.panel = panel, diag.panel = NULL, text.panel = textPanel, label.pos = 0.5 + has.diag/3, cex.labels = NULL, font.labels = 1, row1attop = TRUE, gap = 1) { textPanel &lt;- function(x = 0.5, y = 0.5, txt, cex, font) text(x, y, txt, cex = cex, font = font) localAxis &lt;- function(side, x, y, xpd, bg, col = NULL, main, oma, ...) { if (side%%2 == 1) Axis(x, side = side, xpd = NA, ...) else Axis(y, side = side, xpd = NA, ...) } localPlot &lt;- function(..., main, oma, font.main, cex.main) { plot(...) } localLowerPanel &lt;- function(..., main, oma, font.main, cex.main) lower.panel(...) localUpperPanel &lt;- function(..., main, oma, font.main, cex.main) upper.panel(...) localDiagPanel &lt;- function(..., main, oma, font.main, cex.main) diag.panel(...) dots &lt;- list(...) nmdots &lt;- names(dots) if (!is.matrix(x)) { x &lt;- as.data.frame(x) for (i in seq_along(names(x))) { if (is.factor(x[[i]]) || is.logical(x[[i]])) x[[i]] &lt;- as.numeric(x[[i]]) if (!is.numeric(unclass(x[[i]]))) stop(&quot;non-numeric argument to 'pairs'&quot;) } } else if (!is.numeric(x)) stop(&quot;non-numeric argument to 'pairs'&quot;) panel &lt;- match.fun(panel) if ((has.lower &lt;- !is.null(lower.panel)) &amp;&amp; !missing(lower.panel)) lower.panel &lt;- match.fun(lower.panel) if ((has.upper &lt;- !is.null(upper.panel)) &amp;&amp; !missing(upper.panel)) upper.panel &lt;- match.fun(upper.panel) if ((has.diag &lt;- !is.null(diag.panel)) &amp;&amp; !missing(diag.panel)) diag.panel &lt;- match.fun(diag.panel) if (row1attop) { tmp &lt;- lower.panel lower.panel &lt;- upper.panel upper.panel &lt;- tmp tmp &lt;- has.lower has.lower &lt;- has.upper has.upper &lt;- tmp } nc &lt;- ncol(x) if (nc &lt; 2) stop(&quot;only one column in the argument to 'pairs'&quot;) has.labs &lt;- TRUE if (missing(labels)) { labels &lt;- colnames(x) if (is.null(labels)) labels &lt;- paste(&quot;var&quot;, 1L:nc) } else if (is.null(labels)) has.labs &lt;- FALSE oma &lt;- if (&quot;oma&quot; %in% nmdots) dots$oma else NULL main &lt;- if (&quot;main&quot; %in% nmdots) dots$main else NULL if (is.null(oma)) { oma &lt;- c(4, 4, 4, 4) if (!is.null(main)) oma[3L] &lt;- 6 } opar &lt;- par(mfrow = c(nc, nc), mar = rep.int(gap/2, 4), oma = oma) on.exit(par(opar)) dev.hold() on.exit(dev.flush(), add = TRUE) for (i in if (row1attop) 1L:nc else nc:1L) for (j in 1L:nc) { #print(paste(i,&quot;vs&quot;, j)); xvals = x[,j] yvals = x[,i] if ( (i != j) &amp;&amp; ! is.null(XY_convert_fun)) { res = XY_convert_fun(xvals, yvals); xvals = res[['x']] yvals = res[['y']] } col='black' # default if (! is.null(CustomColorFun)) col=CustomColorFun(xvals,yvals) # get_list_from_ellipsis2 &lt;- function(...) as.list(substitute(list(...)))[-1L] # print(get_list_from_ellipsis2(...));stop(); localPlot(xvals, yvals, xlab = &quot;&quot;, ylab = &quot;&quot;,axes = F, #col=ifelse(abs(xvals-yvals)&gt;2, 'red', 'black'), type = &quot;n&quot;, ...) if (i == j || (i &lt; j &amp;&amp; has.lower) || (i &gt; j &amp;&amp; has.upper)) { box() # edited here... # if (i == 1 &amp;&amp; (!(j%%2) || !has.upper || !has.lower)) # localAxis(1 + 2 * row1attop, x[, j], x[, i], # ...) # draw x-axis if (i != j) #(i == nc &amp; j != nc) localAxis(1, xvals, yvals, ...) # draw y-axis if (j != i) #(j == 1 &amp; i != 1) localAxis(2, xvals, yvals, ...) # if (j == nc &amp;&amp; (i%%2 || !has.upper || !has.lower)) # localAxis(4, x[, j], x[, i], ...) mfg &lt;- par(&quot;mfg&quot;) if (i == j) { if (has.diag) localDiagPanel(as.vector(yvals), ...) if (has.labs) { par(usr = c(0, 1, 0, 1)) if (is.null(cex.labels)) { l.wid &lt;- strwidth(labels, &quot;user&quot;) cex.labels &lt;- max(0.8, min(2, 0.9/max(l.wid))) } text.panel(0.5, label.pos, labels[i], cex = cex.labels, font = font.labels) } } else if (i &lt; j) localLowerPanel(as.vector(xvals), as.vector(yvals), col=col, ...) else localUpperPanel(as.vector(xvals), as.vector(yvals), col=col, ...) if (any(par(&quot;mfg&quot;) != mfg)) stop(&quot;the 'panel' function made a new plot&quot;) } else par(new = FALSE) } if (!is.null(main)) { font.main &lt;- if (&quot;font.main&quot; %in% nmdots) dots$font.main else par(&quot;font.main&quot;) cex.main &lt;- if (&quot;cex.main&quot; %in% nmdots) dots$cex.main else par(&quot;cex.main&quot;) mtext(main, 3, 3, TRUE, 0.5, cex = cex.main, font = font.main) } invisible(NULL) }## Demo it:demo_pairs3 = function (custom_fun=F) { data(iris) xy_conv = function(x,y) { res = list(); res[['x']] = (x+y)/2; res[['y']] = x - y; return(res); } if (custom_fun) { pairs3(iris[1:4], XY_convert_fun = xy_conv, main = &quot;Anderson's Iris Data -- 3 species&quot;,pch = 21, bg = c(&quot;red&quot;, &quot;green3&quot;, &quot;blue&quot;)[unclass(iris$Species)]) } else { pairs3(iris[1:4], main = &quot;Anderson's Iris Data -- 3 species&quot;,pch = 21, bg = c(&quot;red&quot;, &quot;green3&quot;, &quot;blue&quot;)[unclass(iris$Species)]) }} vioplot2.R123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115# from: https://github.com/trinityrnaseq/trinityrnaseq/blob/master/Analysis/DifferentialExpression/R/vioplot2.R#################################################################################### From: https://stackoverflow.com/questions/22410606/violin-plot-with-list-input## and slightly modified to my liking here.vioplot2&lt;-function (x, ..., range = 1.5, h = NULL, ylim = NULL, names = NULL, horizontal = FALSE, col = c(&quot;magenta&quot;), border = &quot;black&quot;, lty = 1, lwd = 1, rectCol = &quot;black&quot;, colMed = &quot;white&quot;, pchMed = 19, at, add = FALSE, wex = 1, drawRect = TRUE){ library(sm) if(!is.list(x)){ datas &lt;- list(x, ...) } else{ datas&lt;-x } n &lt;- length(datas) if (missing(at)) at &lt;- 1:n upper &lt;- vector(mode = &quot;numeric&quot;, length = n) lower &lt;- vector(mode = &quot;numeric&quot;, length = n) q1 &lt;- vector(mode = &quot;numeric&quot;, length = n) q3 &lt;- vector(mode = &quot;numeric&quot;, length = n) med &lt;- vector(mode = &quot;numeric&quot;, length = n) base &lt;- vector(mode = &quot;list&quot;, length = n) height &lt;- vector(mode = &quot;list&quot;, length = n) baserange &lt;- c(Inf, -Inf) args &lt;- list(display = &quot;none&quot;) if (!(is.null(h))) args &lt;- c(args, h = h) for (i in 1:n) { data &lt;- datas[[i]] data.min &lt;- min(data) data.max &lt;- max(data) q1[i] &lt;- quantile(data, 0.25) q3[i] &lt;- quantile(data, 0.75) med[i] &lt;- median(data) iqd &lt;- q3[i] - q1[i] upper[i] &lt;- min(q3[i] + range * iqd, data.max) lower[i] &lt;- max(q1[i] - range * iqd, data.min) est.xlim &lt;- c(min(lower[i], data.min), max(upper[i], data.max)) smout &lt;- do.call(&quot;sm.density&quot;, c(list(data, xlim = est.xlim), args)) hscale &lt;- 0.4/max(smout$estimate) * wex base[[i]] &lt;- smout$eval.points height[[i]] &lt;- smout$estimate * hscale t &lt;- range(base[[i]]) baserange[1] &lt;- min(baserange[1], t[1]) baserange[2] &lt;- max(baserange[2], t[2]) } if (!add) { xlim &lt;- if (n == 1) at + c(-0.5, 0.5) else range(at) + min(diff(at))/2 * c(-1, 1) if (is.null(ylim)) { ylim &lt;- baserange } } if (is.null(names)) { label &lt;- 1:n } else { label &lt;- names } boxwidth &lt;- 0.05 * wex if (!add) plot.new() if (!horizontal) { if (!add) { plot.window(xlim = xlim, ylim = ylim) axis(2) axis(1, at = at, label = label) } box() for (i in 1:n) { polygon(c(at[i] - height[[i]], rev(at[i] + height[[i]])), c(base[[i]], rev(base[[i]])), col = col[i], border = border, lty = lty, lwd = lwd) if (drawRect) { lines(at[c(i, i)], c(lower[i], upper[i]), lwd = lwd, lty = lty) rect(at[i] - boxwidth/2, q1[i], at[i] + boxwidth/2, q3[i], col = rectCol) points(at[i], med[i], pch = pchMed, col = colMed) } } } else { if (!add) { plot.window(xlim = ylim, ylim = xlim) axis(1) axis(2, at = at, label = label) } box() for (i in 1:n) { polygon(c(base[[i]], rev(base[[i]])), c(at[i] - height[[i]], rev(at[i] + height[[i]])), col = col[i], border = border, lty = lty, lwd = lwd) if (drawRect) { lines(c(lower[i], upper[i]), at[c(i, i)], lwd = lwd, lty = lty) rect(q1[i], at[i] - boxwidth/2, q3[i], at[i] + boxwidth/2, col = rectCol) points(med[i], at[i], pch = pchMed, col = colMed) } } } invisible(list(upper = upper, lower = lower, median = med, q1 = q1, q3 = q3))} github: https://github.com/Karobbenblog: Karobben.github.ioR 语言画图索引: https://karobben.github.io/R/R-index.html

