ie = {'Cookie': Cookies} data = { 'color':'16777215', 'fontsize':'25', 'mode':'1', 'msg':MSG, 'rnd':'1584087359', 'roomid':'21154895', 'bubble':'0', 'aid':'56737027', 'csrf_token':'e8377d560fe3434ffd36531d323df842', 'csrf':'e8377d560fe3434ffd36531d323df842' } requests.post('https://api.live.bilibili.com/msg/send', cookies=cookie, data=data)#senddanmu.sendDM(data) #&lt;Response [200]&gt; 200是状态码 表示pass 獲取cookies 方法見視屏:….[還沒上傳] 2 獲取彈幕的方法:用github的項目吧, xfgryujk/blivedm這是我已知的, 最好的彈幕獲取項目 1git clone https://github.com/xfgryujk/blivedm.git 3 聊天模塊用: https://blog.csdn.net/qq_29129381/article/details/82865617這個是最簡單的抄來的代碼, 感謝青云客智能聊天机器人的奉獻 12345678910111213141516171819class airoot(object): #This function is original from:https://blog.csdn.net/qq_29129381/article/details/82865617 def __init__(self): self.url = r'http://api.qingyunke.com/api.php?%s' self.data = { 'key':'free', 'appid':0, 'msg':'' } def getword(self, word=''): self.data['msg'] = word if self.data['msg'] == '': self.data['msg'] = '你不说话, 我来撩你吧' self.params = urllib.parse.urlencode(self.data) self.url = self.url % self.params self.page = urllib.request.urlopen(self.url,timeout=15).read() self.res = json.loads(self.page) self.res['content'] = self.res['content'].replace('{br}',' ') return self.res 4 在blivedm裏面, 加入聊天機器人的代碼 修改sample.py把client ID改成要回覆彈幕的ID 12async def _on_receive_danmaku(self, danmaku: blivedm.DanmakuMessage): print(f'{danmaku.uname}：{danmaku.msg}') 這兩行是彈幕, 直接用後面的{danmaku.msg}就好,這裏, 我們改成 1234async def _on_receive_danmaku(self, danmaku: blivedm.DanmakuMessage): print(f'{danmaku.uname}：{danmaku.msg}') if f'{danmaku.uname}' != &quot;史上最不正經的生物狗&quot;:#這裏是我的名字, 不把自己排除, 會自己套娃, 無限自嗨的= = B_send(airoot().getword(str(f'{danmaku.msg}'))['content']) 彈幕分割因爲普通人員, 一個彈幕只能發20個字節, 字數多了, 會自動忽略, 所以需要分割分佈發送 123def B_Slice(MSG): for i in range((len(MSG)//20)+1): B_send(MSG[i*20:(i+1)*20]) 把分割套進去 1234async def _on_receive_danmaku(self, danmaku: blivedm.DanmakuMessage): print(f'{danmaku.uname}：{danmaku.msg}') if f'{danmaku.uname}' != &quot;史上最不正經的生物狗&quot;: B_Slice(airoot().getword(str(f'{danmaku.msg}'))['content']) 鏈接超時發現經常連接超時, 然後卡在了那裏. 我設置了一個timeout=15, 在前面, 已更新後面老地方, 加一個try 12345678async def _on_receive_danmaku(self, danmaku: blivedm.DanmakuMessage): print(f'{danmaku.uname}：{danmaku.msg}') if f'{danmaku.uname}' != &quot;史上最不正經的生物狗&quot;: try: MSG = airoot().getword(str(f'{danmaku.msg}'))['content'] except: MSG = &quot;鏈接超時了 = =(自動回覆)&quot; B_Slice(MSG) 发送太快而被吞加一个1s延迟,发送弹幕过多的时候 1234def B_Slice(MSG): for i in range((len(MSG)//20)+1): B_send(MSG[i*20:(i+1)*20]) time.sleep(1) 娛樂而已, 應該不會載更新了, /摔板凳 Sample.py123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101# -*- coding: utf-8 -*-import asyncio,requests, sys, timeimport urllib.requestimport urllib.parseimport jsonimport blivedmclass MyBLiveClient(blivedm.BLiveClient): # 演示如何自定义handler _COMMAND_HANDLERS = blivedm.BLiveClient._COMMAND_HANDLERS.copy() async def __on_vip_enter(self, command): print(command) _COMMAND_HANDLERS['WELCOME'] = __on_vip_enter # 老爷入场 async def _on_receive_popularity(self, popularity: int): #print(f'当前人气值：{popularity}') AAAAAAAA = 1 async def _on_receive_danmaku(self, danmaku: blivedm.DanmakuMessage): print(f'{danmaku.uname}：{danmaku.msg}') if f'{danmaku.uname}' != &quot;史上最不正經的生物狗&quot;: try: MSG = airoot().getword(str(f'{danmaku.msg}'))['content'] except: MSG = &quot;鏈接超時了 = =(自動回覆)&quot; B_Slice(MSG) async def _on_receive_gift(self, gift: blivedm.GiftMessage): print(f'{gift.uname} 赠送{gift.gift_name}x{gift.num} （{gift.coin_type}币x{gift.total_coin}）') async def _on_buy_guard(self, message: blivedm.GuardBuyMessage): print(f'{message.username} 购买{message.gift_name}') async def _on_super_chat(self, message: blivedm.SuperChatMessage): print(f'醒目留言 ¥{message.price} {message.uname}：{message.message}')class airoot(object): #This function is original from:https://blog.csdn.net/qq_29129381/article/details/82865617 def __init__(self): self.url = r'http://api.qingyunke.com/api.php?%s' self.data = { 'key':'free', 'appid':0, 'msg':'' } def getword(self, word=''): self.data['msg'] = word if self.data['msg'] == '': self.data['msg'] = '你不说话, 我来撩你吧' self.params = urllib.parse.urlencode(self.data) self.url = self.url % self.params self.page = urllib.request.urlopen(self.url,timeout=15).read() self.res = json.loads(self.page) self.res['content'] = self.res['content'].replace('{br}',' ') return self.resdef B_send(MSG): Cookies = &quot;&quot;#自己的 cookie = {'Cookie': Cookies} data = { 'color':'16777215', 'fontsize':'25', 'mode':'1', 'msg':MSG, 'rnd':'1584087359', 'roomid':'21154895', 'bubble':'0', 'aid':'56737027', 'csrf_token':'e8377d560fe3434ffd36531d323df842', 'csrf':'e8377d560fe3434ffd36531d323df842' } requests.post('https://api.live.bilibili.com/msg/send', cookies=cookie, data=data)#senddanmu.sendDM(data) #&lt;Response [200]&gt; 200是状态码 表示passdef B_Slice(MSG): for i in range((len(MSG)//20)+1): B_send(MSG[i*20:(i+1)*20]) time.sleep(1)async def main(): # 参数1是直播间ID # 如果SSL验证失败就把ssl设为False client = MyBLiveClient(21154895, ssl=True) future = client.start() try: # 5秒后停止，测试用 # await asyncio.sleep(5) # future = client.stop() # 或者 # future.cancel() await future finally: await client.close()if __name__ == '__main__': asyncio.get_event_loop().run_until_complete(main()) 用戶自主開啓關閉機器人有時候機器人實在是太煩了, 簡直煩到想取關這裏, 我們可以添加一個屏蔽名單, 並用簡單的命令判斷,讓發彈幕的人, 自主選擇, 打開或者關閉機器人回答爲了長久有效, 我們最好是, 把這個名單存入本地文件. 這裏, 取名IgnoreList,我直接把他放進同樣的路徑, 方便讀取. 12345678910111213141516def IgnoreList(USER,MSG): Ignore_List = open(sys.path[0]+&quot;/IgnoreList&quot;,'r').read().split(&quot;
